import{_ as a,o as r,c as l,ae as e}from"./chunks/framework.DAK3ioSj.js";const c=JSON.parse('{"title":"Agent Skills 标准","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skills-standard.md","filePath":"radar/tech-skills-standard.md"}'),o={name:"radar/tech-skills-standard.md"};function i(n,t,s,d,h,u){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="agent-skills-标准" tabindex="-1">Agent Skills 标准 <a class="header-anchor" href="#agent-skills-标准" aria-label="Permalink to &quot;Agent Skills 标准&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 管理 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.56</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 跨平台 Skill 格式与协议的开放标准 —— 解决&quot;同一 Skill 在不同 Agent 框架上格式互通&quot;问题。</p><p><strong>来源</strong>:</p><ul><li>社区开放标准</li><li>仅规范级别（非具体产品）</li></ul><p><strong>链接</strong>:</p><ul><li>官网：<a href="https://agentskills.io/" target="_blank" rel="noreferrer">agentskills.io</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="标准化目标" tabindex="-1">标准化目标 <a class="header-anchor" href="#标准化目标" aria-label="Permalink to &quot;标准化目标&quot;">​</a></h3><p>定义跨 Agent 平台（Claude / Gemini / OpenAI / LangChain / Cursor 等）的统一 Skill 格式与协议，让一份 Skill 文件可被所有合规框架消费。</p><h3 id="现状判断" tabindex="-1">现状判断 <a class="header-anchor" href="#现状判断" aria-label="Permalink to &quot;现状判断&quot;">​</a></h3><ul><li>已发布初版规范</li><li>部分工具（如 Skill Seekers）声称支持 20 个平台格式 —— 但<strong>没有验证&quot;转换后的 Skill 在目标平台上效果是否与源平台一致&quot;</strong></li><li><strong>格式兼容 ≠ 行为一致</strong> —— 同一个 Skill 在 Claude Code 和 OpenCode 上即使格式兼容，执行行为也可能完全不同</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>仅是<strong>规范级别</strong>，无强制约束力</li><li>不解决跨框架的<strong>行为一致性</strong>问题（只解决格式兼容）</li><li>缺乏权威治理机构和合规测试套件</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>规范已发布</td></tr><tr><td>创新性</td><td>0.50</td><td>跨平台标准化思路成熟，但落地新</td></tr><tr><td>落地程度</td><td>0.55</td><td>已被多个工具引用</td></tr><tr><td>生态活跃度</td><td>0.60</td><td>开放标准，社区参与</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.56</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://agentskills.io/" target="_blank" rel="noreferrer">agentskills.io</a></li></ul>',26)])])}const k=a(o,[["render",i]]);export{c as __pageData,k as default};
